// ========== 工具函数（XSS 防护） ==========
function escapeHtml(s) {
    if (s == null) return '';
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}
function safeId(s) {
    if (s == null) return '';
    return String(s).replace(/[^a-zA-Z0-9_-]/g, '');
}

