// 从localStorage加载数据
function loadDeviceData() {
    var saved = localStorage.getItem(DEVICE_STORAGE_KEY);
    if (saved) {
        try {
            var data = JSON.parse(saved);
            orgMap = data.orgMap || {};
            deviceData = data.deviceData || {};
            if (typeof hasEncKey === 'function' && hasEncKey()) {
                Object.keys(deviceData).forEach(function(code) {
                    deviceData[code].forEach(function(d) { decryptDeviceItem(d); });
                });
            }
        } catch(e) {}
    }
}

function decryptDeviceItem(d) {
    d['维护负责人'] = typeof decryptField === 'function' ? decryptField(d['维护负责人']) : d['维护负责人'];
    d['联系方式'] = typeof decryptField === 'function' ? decryptField(d['联系方式']) : d['联系方式'];
}

function encryptDeviceItem(d) {
    d['维护负责人'] = typeof encryptField === 'function' ? encryptField(d['维护负责人']) : d['维护负责人'];
    d['联系方式'] = typeof encryptField === 'function' ? encryptField(d['联系方式']) : d['联系方式'];
}

// 保存到localStorage
function saveDeviceData() {
    var dd = {};
    Object.keys(deviceData).forEach(function(code) {
        dd[code] = deviceData[code].map(function(d) {
            var c = Object.assign({}, d);
            if (typeof hasEncKey === 'function' && hasEncKey()) encryptDeviceItem(c);
            return c;
        });
    });
    localStorage.setItem(DEVICE_STORAGE_KEY, JSON.stringify({orgMap: orgMap, deviceData: dd}));
}

// 页面切换
function showDeviceTab(tab) {
    document.getElementById('device-tab-orgs').style.display = tab === 'orgs' ? 'block' : 'none';
    document.getElementById('device-tab-equipments').style.display = tab === 'equipments' ? 'block' : 'none';
    document.getElementById('tab-btn-orgs').classList.toggle('active', tab === 'orgs');
    document.getElementById('tab-btn-equipments').classList.toggle('active', tab === 'equipments');
    if (tab === 'orgs') renderOrgs();
    else renderDeviceItems();
}

// 渲染网点列表
function renderOrgs() {
    var search = document.getElementById('search-org').value.trim().toLowerCase();
    var html = '';
    var count = 0;
    for (var name in orgMap) {
        if (search && name.toLowerCase().indexOf(search) === -1) continue;
        var code = orgMap[name];
        var deviceCount = deviceData[code] ? deviceData[code].length : 0;
        count++;
        var safeCode = safeId(code);
        // 用 data 属性 + 事件代理避免内联处理器拼接 XSS
        html += '<tr><td>' + escapeHtml(code) + '</td><td>' + escapeHtml(name) + '</td><td>' + deviceCount + '</td>' +
            '<button class="btn btn-link btn-sm p-0 me-2" data-action="view" data-code="' + safeCode + '" data-name="' + escapeHtml(name) + '">查看设备</button>' +
            '<button class="btn btn-link btn-sm p-0 me-2" data-action="edit" data-code="' + safeCode + '">编辑</button>' +
            '<button class="btn btn-link btn-sm text-danger p-0" data-action="delete" data-code="' + safeCode + '" data-name="' + escapeHtml(name) + '">删除</button></td></tr>';
    }
    if (!html) html = '<tr><td colspan="4" class="text-center text-muted">暂无网点数据</td></tr>';
    document.getElementById('org-table').innerHTML = html;
    document.getElementById('org-count').textContent = count;

    // 事件代理
    var tbody = document.getElementById('org-table');
    if (tbody && !tbody._wired) {
        tbody._wired = true;
        tbody.addEventListener('click', function(e) {
            var btn = e.target.closest('button[data-action]');
            if (!btn) return;
            var action = btn.getAttribute('data-action');
            var code = btn.getAttribute('data-code');
            var name = btn.getAttribute('data-name');
            if (action === 'view') viewOrgDevices(code, name);
            else if (action === 'edit') editOrg(code);
            else if (action === 'delete') deleteOrg(code, name);
        });
    }
}

// 新增/编辑网点弹窗
function showOrgModal(code) {
    if (code) {
        document.getElementById('org-modal-title').textContent = '编辑网点';
        document.getElementById('org-old-code').value = code;
        document.getElementById('org-code').value = code;
        // orgMap 结构是 {name: code}，需要反向查找 name
        var currentName = '';
        for (var n in orgMap) { if (orgMap[n] === code) { currentName = n; break; } }
        document.getElementById('org-name').value = currentName;
    } else {
        document.getElementById('org-modal-title').textContent = '新增网点';
        document.getElementById('org-old-code').value = '';
        document.getElementById('org-code').value = '';
        document.getElementById('org-name').value = '';
    }
    new bootstrap.Modal(document.getElementById('orgModal')).show();
}

function editOrg(code) { showOrgModal(code); }

function saveOrg() {
    var oldCode = document.getElementById('org-old-code').value;
    var code = document.getElementById('org-code').value.trim();
    var name = document.getElementById('org-name').value.trim();
    if (!code || !name) { alert('请填写完整信息'); return; }

    // 如果编号改变，需要迁移设备数据
    if (oldCode && oldCode !== code) {
        if (deviceData[oldCode]) {
            deviceData[code] = deviceData[oldCode];
            delete deviceData[oldCode];
        }
        // orgMap 结构是 {name: code}，删除所有 name→oldCode 的映射
        for (var nn in orgMap) { if (orgMap[nn] === oldCode) delete orgMap[nn]; }
    }
    orgMap[name] = code;
    saveDeviceData();
    bootstrap.Modal.getInstance(document.getElementById('orgModal')).hide();
    renderOrgs();
    updateDeviceOrgSelect();
}

function deleteOrg(code, name) {
    if (!confirm('确定删除网点「' + (name || code) + '」吗？设备数据也会被删除。')) return;
    // orgMap 结构是 {name: code}，删除所有 name→code 的映射
    for (var n in orgMap) { if (orgMap[n] === code) delete orgMap[n]; }
    delete deviceData[code];
    saveDeviceData();
    renderOrgs();
}

// 查看网点设备
function viewOrgDevices(code, name) {
    document.getElementById('view-org-title').textContent = (name || '') + ' - 设备列表';
    var devices = deviceData[code] || [];
    var html = '';
    var safeCode = safeId(code);
    devices.forEach(function(d, idx) {
        html += '<tr><td>' + escapeHtml(d.设备类型) + '</td><td>' + escapeHtml(d.设备品牌) + '</td><td>' + escapeHtml(d.设备维护商) + '</td>' +
            '<td>' + escapeHtml(d.维护负责人) + '</td><td>' + escapeHtml(d.联系方式) + '</td><td>' + escapeHtml(d.备注) + '</td>' +
            '<td><button class="btn btn-link btn-sm p-0" data-action="edit-device" data-code="' + safeCode + '" data-idx="' + idx + '">编辑</button> ' +
            '<button class="btn btn-link btn-sm text-danger p-0" data-action="delete-device" data-code="' + safeCode + '" data-idx="' + idx + '">删除</button></td></tr>';
    });
    if (!html) html = '<tr><td colspan="7" class="text-center text-muted">暂无设备</td></tr>';
    var table = document.getElementById('view-org-devices-table');
    table.innerHTML = html;
    if (!table._wired) {
        table._wired = true;
        table.addEventListener('click', function(e) {
            var btn = e.target.closest('button[data-action]');
            if (!btn) return;
            var action = btn.getAttribute('data-action');
            var code = btn.getAttribute('data-code');
            var idx = parseInt(btn.getAttribute('data-idx'), 10);
            if (action === 'edit-device') editDeviceItem(code, idx);
            else if (action === 'delete-device') deleteDeviceItem(code, idx);
        });
    }
    new bootstrap.Modal(document.getElementById('viewOrgDevicesModal')).show();
}

// 渲染设备列表
function renderDeviceItems() {
    var orgFilter = document.getElementById('filter-device-org').value;
    var search = document.getElementById('search-device-item').value.trim().toLowerCase();
    var html = '';
    for (var code in deviceData) {
        var orgName = '';
        for (var n in orgMap) { if (orgMap[n] === code) { orgName = n; break; } }
        deviceData[code].forEach(function(d, idx) {
            if (orgFilter && code !== orgFilter) return;
            if (search) {
                var match = (d.设备品牌||'').toLowerCase().indexOf(search) !== -1 ||
                    (d.维护负责人||'').toLowerCase().indexOf(search) !== -1 ||
                    (d.设备维护商||'').toLowerCase().indexOf(search) !== -1;
                if (!match) return;
            }
            var safeCode = safeId(code);
            html += '<tr><td>' + escapeHtml(orgName) + '</td><td>' + escapeHtml(d.设备类型) + '</td><td>' + escapeHtml(d.设备品牌) + '</td>' +
                '<td>' + escapeHtml(d.设备维护商) + '</td><td>' + escapeHtml(d.维护负责人) + '</td><td>' + escapeHtml(d.联系方式) + '</td>' +
                '<td>' + escapeHtml(d.备注) + '</td>' +
                '<td><button class="btn btn-link btn-sm p-0" data-action="edit-device" data-code="' + safeCode + '" data-idx="' + idx + '">编辑</button> ' +
                '<button class="btn btn-link btn-sm text-danger p-0" data-action="delete-device" data-code="' + safeCode + '" data-idx="' + idx + '">删除</button></td></tr>';
        });
        // 事件代理只挂一次
        if (!renderDeviceItems._wired) {
            var tbl = document.getElementById('device-item-table');
            if (tbl) {
                renderDeviceItems._wired = true;
                tbl.addEventListener('click', function(e) {
                    var btn = e.target.closest('button[data-action]');
                    if (!btn) return;
                    var action = btn.getAttribute('data-action');
                    var code = btn.getAttribute('data-code');
                    var idx = parseInt(btn.getAttribute('data-idx'), 10);
                    if (action === 'edit-device') editDeviceItem(code, idx);
                    else if (action === 'delete-device') deleteDeviceItem(code, idx);
                });
            }
        }
    }
    if (!html) html = '<tr><td colspan="8" class="text-center text-muted">暂无设备数据</td></tr>';
    document.getElementById('device-item-table').innerHTML = html;
}

// 新增/编辑设备弹窗
function showDeviceItemModal(code, idx) {
    document.getElementById('di-idx').value = code || '';
    document.getElementById('di-device-idx').value = idx !== undefined ? idx : '';

    updateDeviceOrgSelect();

    if (code && idx !== undefined && deviceData[code]) {
        var d = deviceData[code][idx];
        document.getElementById('di-modal-title').textContent = '编辑设备';
        document.getElementById('di-org').value = code;
        document.getElementById('di-type').value = d.设备类型 || '';
        document.getElementById('di-brand').value = d.设备品牌 || '';
        document.getElementById('di-vendor').value = d.设备维护商 || '';
        document.getElementById('di-contact').value = d.维护负责人 || '';
        document.getElementById('di-phone').value = d.联系方式 || '';
        document.getElementById('di-remark').value = d.备注 || '';
    } else {
        document.getElementById('di-modal-title').textContent = '新增设备';
        document.getElementById('di-type').value = '';
        document.getElementById('di-brand').value = '';
        document.getElementById('di-vendor').value = '';
        document.getElementById('di-contact').value = '';
        document.getElementById('di-phone').value = '';
        document.getElementById('di-remark').value = '';
    }
    new bootstrap.Modal(document.getElementById('deviceItemModal')).show();
}

function editDeviceItem(code, idx) {
    showDeviceItemModal(code, idx);
}

function saveDeviceItem() {
    var orgCode = document.getElementById('di-org').value;
    var type = document.getElementById('di-type').value.trim();
    var brand = document.getElementById('di-brand').value.trim();
    var vendor = document.getElementById('di-vendor').value.trim();
    var contact = document.getElementById('di-contact').value.trim();
    var phone = document.getElementById('di-phone').value.trim();
    var remark = document.getElementById('di-remark').value.trim();

    if (!orgCode) { alert('请选择所属网点'); return; }
    if (!type) { alert('请输入设备类型'); return; }

    var device = {
        '设备类型': type,
        '设备品牌': brand,
        '设备维护商': vendor,
        '维护负责人': contact,
        '联系方式': phone,
        '备注': remark
    };

    if (!deviceData[orgCode]) deviceData[orgCode] = [];

    var oldCode = document.getElementById('di-idx').value;
    var deviceIdx = document.getElementById('di-device-idx').value;

    if (oldCode && deviceIdx !== '') {
        // 编辑
        if (oldCode === orgCode) {
            deviceData[orgCode][parseInt(deviceIdx)] = device;
        } else {
            // 移动到其他网点
            deviceData[oldCode].splice(parseInt(deviceIdx), 1);
            deviceData[orgCode].push(device);
        }
    } else {
        // 新增
        deviceData[orgCode].push(device);
    }

    saveDeviceData();
    bootstrap.Modal.getInstance(document.getElementById('deviceItemModal')).hide();
    renderDeviceItems();
}

function deleteDeviceItem(code, idx) {
    if (!confirm('确定删除此设备吗？')) return;
    if (deviceData[code]) {
        deviceData[code].splice(idx, 1);
        saveDeviceData();
        renderDeviceItems();
        // 如果在查看弹窗中，更新查看列表
        var modal = document.getElementById('viewOrgDevicesModal');
        if (modal.classList.contains('show')) {
            for (var n in orgMap) { if (orgMap[n] === code) { viewOrgDevices(code, n); break; } }
        }
    }
}

// 更新网点选择下拉框
function updateDeviceOrgSelect() {
    var html = '';
    for (var name in orgMap) {
        html += '<option value="' + orgMap[name] + '">' + name + '</option>';
    }
    document.getElementById('di-org').innerHTML = html;
    document.getElementById('filter-device-org').innerHTML = '<option value="">全部网点</option>' + html;
}

// 云端同步 - 设备数据
async function syncDevicesToGist() {
    var token = localStorage.getItem(GIST_TOKEN_KEY);
    if (!token) { alert('请先在系统设置中配置GitHub Token'); return; }
    try {
        var content = JSON.stringify({orgMap: orgMap, deviceData: deviceData}, null, 2);
        var res = await fetch('https://api.github.com/gists/' + FIXED_GIST_ID, {
            method: 'PATCH',
            headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
            body: JSON.stringify({ description: '网点设备数据同步', files: { 'deviceData.json': { content: content } } })
        });
        if (res.ok) { alert('设备数据已同步至云端！'); }
        else { alert('同步失败，HTTP错误：' + res.status); }
    } catch(err) { alert('同步失败：' + err.message); }
}

async function syncDevicesFromGist() {
    var token = localStorage.getItem(GIST_TOKEN_KEY);
    try {
        var res = await fetch('https://api.github.com/gists/' + FIXED_GIST_ID, {
            headers: token ? { 'Authorization': 'Bearer ' + token } : {}
        });
        var data = await res.json();
        if (data.files && data.files['deviceData.json']) {
            var cloudData = JSON.parse(data.files['deviceData.json'].content);
            orgMap = cloudData.orgMap || {};
            deviceData = cloudData.deviceData || {};
            saveDeviceData();
            alert('已从云端拉取设备数据！');
            renderOrgs();
            updateDeviceOrgSelect();
        } else {
            alert('云端暂无设备数据');
        }
    } catch(err) { alert('拉取失败：' + err.message); }
}

